import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Link } from 'react-router-dom';
import { AppProvider, useApp } from './context/AppContext';

// Auth components
import RegisterForm from './components/auth/RegisterForm';
import LoginForm from './components/auth/LoginForm';
import AdminLogin from './components/auth/AdminLogin';
import UserProfile from './components/auth/UserProfile';

// Flight components
import FlightSearch from './components/flights/FlightSearch';
import AdminFlightList from './components/flights/admin/AdminFlightList';

// Common
import ProtectedRoute from './components/common/ProtectedRoute';

import './App.css';

// Navbar shown after login
const Navbar = () => {
  const { user, isAdmin, logout } = useApp();
  if (!user) return null;

  return (
    <nav className="navbar">
      <div className="nav-brand">✈ SkyReserve</div>
      <div className="nav-links">
        {!isAdmin && <Link to="/flights">Search Flights</Link>}
        {isAdmin && <Link to="/admin/flights">Manage Flights</Link>}
        <Link to="/profile">Profile</Link>
        {isAdmin && <span className="admin-tag">ADMIN</span>}
        <button className="nav-logout" onClick={logout}>Logout</button>
      </div>
    </nav>
  );
};

const AppRoutes = () => {
  const { user, isAdmin } = useApp();

  return (
    <>
      <Navbar />
      <Routes>
        {/* Public routes */}
        <Route path="/register" element={<RegisterForm />} />
        <Route path="/login" element={<LoginForm />} />
        <Route path="/admin-login" element={<AdminLogin />} />

        {/* Protected user routes */}
        <Route path="/flights" element={
          <ProtectedRoute><FlightSearch /></ProtectedRoute>
        } />
        <Route path="/profile" element={
          <ProtectedRoute><UserProfile /></ProtectedRoute>
        } />

        {/* Protected admin routes */}
        <Route path="/admin/flights" element={
          <ProtectedRoute adminOnly><AdminFlightList /></ProtectedRoute>
        } />

        {/* Default redirect */}
        <Route path="/" element={
          user
            ? (isAdmin ? <Navigate to="/admin/flights" replace /> : <Navigate to="/flights" replace />)
            : <Navigate to="/login" replace />
        } />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </>
  );
};

function App() {
  return (
    <AppProvider>
      <Router>
        <AppRoutes />
      </Router>
    </AppProvider>
  );
}

export default App;
